VALUES
  ('aboriginal-f0899a01-moex-00617', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依再生能源發展條例第9條規定：「中央主管機關應邀集相關各部會、學者專家、團體組成委員會， 審定再生能源發電設備生產電能之躉購費率及其計算公式，必要時得依行政程序法舉辦聽證會後公告 之。」關於此規定，下列敘述何者正確？ 該聽證得依當事人之申請，由主持人決定全部不公開 該聽證具有終結程序之效力，行政機關不得再為聽證 該躉購費率與計算公式之公告，屬於裁量性行政規則 該費率審定委員會之性質，屬於獨立的行政管制機關', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00618', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '行政機關基於法律授權，對多數不特定人民就一般事項所作抽象之對外發生法律效果之規定。稱為： 法規命令  職權命令  行政規則  緊急命令', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00619', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列行政處分何者得撤銷？ 未表明處分機關之行政處分  許可違法之賭博 對已死亡之人作成之行政處分  未明確敘明違法事證所為之裁罰處分', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00620', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '國營金融機構以函文檢送主管機關之公函通知各退休人員關於新優惠存款改革方案內容，涉及相對人 權益變更。其法律性質為何？ 行政處分  事實行為  行政契約  私法行為', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00621', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於違法行政處分撤銷之敘述，下列何者錯誤？ 2年撤銷期限為除斥期間 撤銷原因包括認定事實及適用法規之瑕疵 自有權撤銷機關確實知曉原處分違法，起算除斥期間 僅上級機關得撤銷違法行政處分', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00622', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '對於行政處分聲明不服，因處分機關未為告知或告知錯誤致向無管轄權之機關為之者，該機關依行政 程序法之規定，應於幾日內移送有管轄權之機關？ 7日  10日  20日  30日', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00623', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關行政契約的雙務契約之敘述，下列何者正確？ 為避免產生違法瑕疵，下級機關所締結之雙務契約應經上級機關之核准 基於無效雙務行政契約所為之行政處分為違法行政處分，得依職權撤銷 契約為雙方行為，故因其履行而權利將受侵害之第三人不得聲請假處分 行政機關與人民締結行政契約以代替行政處分，原則上仍得再為該處分', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00624', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依據行政程序法之規定，下列何種行為原則上應以書面為之？ 行政處分  行政契約  行政指導  陳情', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00625', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬事實行為？ 交通部中央氣象局發布特定地區寒害特報 行政院農業委員會呼籲農民不要搶種高麗菜 環境影響評估審查委員會作成環境影響評估審查 外交部對於特定地區進行旅遊警示', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00626', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '進口人填具進口報單時，需分別填載進口稅、貨物稅及營業稅相關事項，向海關遞交，始完成申報， 如未據實申報，即構成逃漏進口稅、貨物稅及營業稅。依據實務見解，下列敘述何者錯誤？ 構成3個違序行為，應處3個逃漏稅罰鍰 構成3個違序行為，罰鍰部分應併合處罰 構成1個違序行為，罰鍰部分應併合處罰 罰鍰部分併合處罰與一行為不二罰之原則並無牴觸', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:35+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
